setze.syntax:
setze [der/die/das/den/dem/des inhalt von] {target} von {source}
set [der/die/das/den/dem/des] titel zu {title}
set [der/die/das/den/dem/des] inhalt von {element} zu {value}
set [der/die/das/den/dem/des] id von {element} zu {id} [als {selected}]
set [der/die/das/den/dem/des] text von {button}/{input}/{span}/{label} zu {text}
set [der/die/das/den/dem/des] größe/groesse von {input} zu {size}
set attribut {name} von {element} zu {value}
set stil {name} von {element}/körper/koerper zu {style}
set [der/die/das/den/dem/des] stile von {element} zu {styles}
set [der/die/das/den/dem/des] standard von {select} zu {value}
set {select} von List [als {value}]
